    const vowels = ['a', 'e', 'i', 'o', 'u'];
    const n = s.length;

    // 1. Count frequencies and record first appearance index for each vowel
    const freq = {};
    const firstIndex = {};

    for (let i = 0; i < n; i++) {
        const char = s[i];
        if (vowels.includes(char)) {
            freq[char] = (freq[char] || 0) + 1;
            if (firstIndex[char] === undefined) {
                firstIndex[char] = i;
            }
        }
    }

    // 2. Get unique vowels present and create a list of objects for sorting
    const vowelData = [];
    for (const char of vowels) {
        if (freq[char]) {
            vowelData.push({
                char: char,
                count: freq[char],
                firstPos: firstIndex[char]
            });
        }
    }

    // 3. Sort the vowels based on the criteria:
    //    a) Non-increasing frequency (descending count)
    //    b) If frequencies are equal, sort by first appearance position (ascending firstPos)
    vowelData.sort((a, b) => {
        // Compare frequencies (descending order)
        if (b.count !== a.count) {
            return b.count - a.count;
        }
        // Frequencies are equal, compare first appearance position (ascending order)
        return a.firstPos - b.firstPos;
    });

    // 4. Build the result string
    const resultArr = s.split('');

    // Map to hold the sequence of sorted vowels
    const sortedVowelSequence = [];
    for (const vd of vowelData) {
        for (let i = 0; i < vd.count; i++) {
            sortedVowelSequence.push(vd.char);
        }
    }

    // Iterate through the original string and replace vowels based on the sorted sequence
    let sortedVowelIndex = 0;
    for (let i = 0; i < n; i++) {
        if (vowels.includes(s[i])) {
            resultArr[i] = sortedVowelSequence[sortedVowelIndex];
            sortedVowelIndex++;
        }
    }

    return resultArr.join('');
}

